10	import { ChangeTracker, captureContents } from './changeTracker.js';
11	import { evaluateToolUse, getPolicy } from './policyEngine.js';
12	
13	let _id = 0;
14	const nextId = () => `s${Date.now().toString(36)}${(_id++).toString(36)}`;
15	
16	const MAX_EVENTS = 5000;
17	
18	export class SessionManager extends EventEmitter {
19	  constructor({ store } = {}) {
20	    super();
21	    this.sessions = new Map();
22	    this.store = store || null;
23	  }
24	
25	  list() {
26	    return Array.from(this.sessions.values()).map((s) => s.summary());
27	  }
28	
29	  get(id) {
30	    return this.sessions.get(id);
31	  }
32	
33	  create({ workdir, name, policyId }) {
34	    let abs = path.resolve(workdir || process.cwd());
35	    if (!fs.existsSync(abs) || !fs.statSync(abs).isDirectory()) {
36	      throw new Error(`工作目录不存在: ${abs}`);
37	    }
38	    // Resolve symlinks (e.g. /tmp -> /private/tmp on macOS) so paths the
39	    // CLI reports later match the workdir we record.
40	    try {
41	      abs = fs.realpathSync(abs);
42	    } catch {}
43	    const session = new Session({
44	      id: nextId(),
45	      workdir: abs,
46	      name: name || path.basename(abs),
47	      policyId: policyId || 'balanced',
48	      bus: this,
49	    });
50	    session._store = this.store;
51	    this.sessions.set(session.id, session);
52	    this.emit('session:created', session.summary());
53	    this.store?.scheduleSave(session);
54	    return session;
55	  }
56	
57	  remove(id) {
58	    const s = this.sessions.get(id);
59	    if (!s) return false;
60	    s.stop();
61	    this.sessions.delete(id);
62	    this.store?.remove(id);
63	    this.emit('session:removed', { id });
64	    return true;
65	  }
66	
67	  // Rebuild a Session from a persisted payload after a server restart.
68	  // Live-only fields (activeChild/activeTurn/pendingApprovals) are reset,
69	  // and a synthetic `session:interrupted` event is appended so the audit
70	  // log reflects the gap.
71	  hydrate(persisted) {
72	    const session = new Session({
73	      id: persisted.id,
74	      workdir: persisted.workdir,
75	      name: persisted.name,
76	      policyId: persisted.policyId,
77	      bus: this,
78	    });
79	    session._store = this.store;
80	
81	    // Restore audit/state fields verbatim.
82	    session.createdAt = persisted.createdAt;
83	    session.endedAt = persisted.endedAt;
84	    session.claudeSessionId = persisted.claudeSessionId || null;
85	    session.turns = Array.isArray(persisted.turns) ? persisted.turns : [];
86	    session.events = Array.isArray(persisted.events) ? persisted.events : [];
87	    session.tools = Array.isArray(persisted.tools) ? persisted.tools : [];
88	    session.changes = Array.isArray(persisted.changes) ? persisted.changes : [];
89	    session.lastChangeMap = persisted.lastChangeMap || {};
90	    session.fileBaselines = persisted.fileBaselines || {};
91	
92	    // Live fields are always fresh.
93	    session.activeChild = null;
94	    session.activeTurn = null;
95	    session.pendingApprovals = new Map();
96	
97	    const workdirOk =
98	      fs.existsSync(persisted.workdir) && fs.statSync(persisted.workdir).isDirectory();
99	    if (workdirOk) {
100	      // Re-snapshot so the next turn diffs against the post-restart state.
101	      session.changeTracker.takeSnapshot();
102	      let status = persisted.status;
103	      if (status === 'running' || status === 'waiting' || status === 'cancelling') status = 'idle';
104	      session.status = status || 'idle';
105	    } else {
106	      session.status = 'error';
107	    }
108	
109	    // Mark any approvals that were pending at shutdown as abandoned.
110	    if (Array.isArray(persisted.pendingApprovals)) {
111	      for (const a of persisted.pendingApprovals) {
112	        session._record({
113	          type: 'approval:abandoned',
114	          toolUseId: a.toolUseId || a.id,
115	          tool: a.tool,
116	        });
117	      }
118	    }
119	
120	    if (!workdirOk) {
121	      session._record({ type: 'session:workdir-missing', workdir: persisted.workdir });
122	    }
123	    session._record({ type: 'session:interrupted' });
124	
125	    this.sessions.set(session.id, session);
126	    this.emit('session:created', session.summary());
127	    return session;
128	  }
129	}
130	
131	class Session {
132	  constructor({ id, workdir, name, policyId, bus }) {
133	    this.id = id;
134	    this.workdir = workdir;
135	    this.name = name;
136	    this.policyId = policyId;
137	    this.bus = bus;
138	
139	    this.createdAt = Date.now();
140	    this.endedAt = null;
141	    this.status = 'idle'; // idle | running | waiting | ended | error
142	    this.claudeSessionId = null;
143	
144	    this.turns = []; // { id, prompt, startedAt, endedAt, status }
145	    this.events = []; // chronological log of EVERY event (audit log)
146	    this.tools = []; // tool_use audit records with policy decision
147	    this.changes = []; // per-turn change sets
148	    this.lastChangeMap = {}; // relPath -> { turn, kind }
149	
150	    this.changeTracker = new ChangeTracker(workdir);
151	    this.changeTracker.takeSnapshot();
152	    this.fileBaselines = {}; // relPath -> content snapshot for diff display
153	
154	    this.activeChild = null;
155	    this.activeTurn = null;
156	    this.pendingApprovals = new Map();
157	  }
158	
159	  summary() {
160	    return {
161	      id: this.id,
162	      name: this.name,
163	      workdir: this.workdir,
164	      policyId: this.policyId,
165	      status: this.status,
166	      createdAt: this.createdAt,
167	      endedAt: this.endedAt,
168	      turnCount: this.turns.length,
169	      changeCount: this.changes.reduce((acc, c) => acc + c.files.length, 0),
170	      pendingApprovals: this.pendingApprovals.size,
171	      claudeSessionId: this.claudeSessionId,
172	    };
173	  }
174	
175	  setPolicy(policyId) {
176	    this.policyId = policyId;
177	    this._record({ type: 'policy:changed', policyId });
178	  }
179	
180	  // ===== Turn execution =====
181	  async sendPrompt(prompt) {
182	    if (this.activeChild) throw new Error('当前会话已有运行中的对话');
183	    const policy = getPolicy(this.policyId);
184	    const turnId = `t${this.turns.length + 1}`;
185	    const turn = {
186	      id: turnId,
187	      prompt,
188	      startedAt: Date.now(),
189	      endedAt: null,
190	      status: 'running',
191	      policyId: policy.id,
192	    };
193	    this.turns.push(turn);
194	    this.activeTurn = turn;
195	
196	    this.status = 'running';
197	    this._record({ type: 'turn:start', turnId, prompt, policyId: policy.id });
198	    this._broadcastSummary();
199	
200	    // Take a snapshot before running so we can diff afterwards.
201	    this.changeTracker.takeSnapshot();
202	
203	    const args = [
204	      '--print',
205	      '--output-format', 'stream-json',
206	      '--verbose',
207	      '--permission-mode', policy.permissionMode,
208	    ];
209	    if (this.claudeSessionId) {
210	      args.push('--resume', this.claudeSessionId);
211	    }
212	    args.push(prompt);
213	
214	    let child;
215	    try {
216	      // detached: true makes the child a process-group leader, so a single
217	      // process.kill(-pid, sig) tears down `claude` and any tool subprocesses
218	      // (Bash, MCP servers, etc.) it spawned. Without this, only the immediate
219	      // child dies and the user sees "停止" do nothing because Bash keeps
220	      // running in the background.
221	      child = spawn('claude', args, {
222	        cwd: this.workdir,
223	        env: { ...process.env, FORCE_COLOR: '0' },
224	        stdio: ['ignore', 'pipe', 'pipe'],
225	        detached: true,
226	      });
227	    } catch (e) {
228	      this._record({ type: 'turn:error', turnId, error: e.message });
229	      turn.status = 'error';
230	      turn.endedAt = Date.now();
231	      this.status = 'error';
232	      this.activeTurn = null;
233	      this._broadcastSummary();
234	      throw e;
235	    }
236	    this.activeChild = child;
237	    this._cancelRequested = false;
238	    if (this._killEscalateTimer) {
239	      clearTimeout(this._killEscalateTimer);
240	      this._killEscalateTimer = null;
241	    }
242	
243	    // Pre-capture baselines for any files that may be edited so we can show
244	    // diffs even after Claude writes them.
245	    // We capture lazily on-demand from snapshot keys.
246	
247	    let stdoutBuf = '';
248	    child.stdout.on('data', (chunk) => {
249	      stdoutBuf += chunk.toString('utf8');
250	      let idx;
251	      while ((idx = stdoutBuf.indexOf('\n')) >= 0) {
252	        const line = stdoutBuf.slice(0, idx).trim();
253	        stdoutBuf = stdoutBuf.slice(idx + 1);
254	        if (line) this._handleStreamLine(line);
255	      }
256	    });
257	
258	    let stderrBuf = '';
259	    child.stderr.on('data', (chunk) => {
260	      stderrBuf += chunk.toString('utf8');
261	    });
262	
263	    child.on('error', (err) => {
264	      this._record({ type: 'turn:error', turnId, error: err.message });
265	      this._endTurn('error', err.message);
266	    });
267	
268	    child.on('close', (code, signal) => {
269	      if (this._killEscalateTimer) {
270	        clearTimeout(this._killEscalateTimer);
271	        this._killEscalateTimer = null;
272	      }
273	      if (stdoutBuf.trim()) this._handleStreamLine(stdoutBuf.trim());
274	      // If the user clicked stop, mark the turn cancelled rather than errored —
275	      // a non-zero exit from a SIGTERM/SIGKILL is expected, not a real failure.
276	      let outcome;
277	      if (this._cancelRequested) outcome = 'cancelled';
278	      else if (code === 0) outcome = 'done';
279	      else outcome = 'error';
280	      if (outcome === 'error' && stderrBuf) {
281	        this._record({ type: 'cli:stderr', text: stderrBuf.trim() });
282	      }
283	      this._afterTurnFinish(outcome, signal);
284	    });
285	
286	    return turn;
287	  }
288	
289	  cancel() {
290	    if (!this.activeChild) return false;
291	    if (this._cancelRequested) return true; // idempotent
292	    this._cancelRequested = true;
293	    this.status = 'cancelling';
294	    this._record({ type: 'turn:cancel', turnId: this.activeTurn?.id });
295	    this._broadcastSummary();
296	    this._signalChildGroup('SIGTERM');
297	    // Escalate to SIGKILL if the process group is still alive after 2.5s.
298	    // Cleared in child.on('close').
299	    this._killEscalateTimer = setTimeout(() => {
300	      if (this.activeChild) {
301	        this._signalChildGroup('SIGKILL');
302	      }
303	    }, 2500);
304	    return true;
305	  }
306	
307	  _signalChildGroup(sig) {
308	    const child = this.activeChild;
309	    if (!child || child.pid == null) return;
310	    // Kill the whole process group (negative pid) so subprocesses go too.
311	    // Falls back to a direct kill if the group call fails (e.g. ESRCH means
312	    // the process is already gone — nothing to do).
313	    try {
314	      process.kill(-child.pid, sig);
315	    } catch (e) {
316	      if (e.code !== 'ESRCH') {
317	        try { child.kill(sig); } catch {}
318	      }
319	    }
320	  }
321	
322	  stop() {
323	    this.cancel();
324	    if (this.status !== 'ended') {
325	      this.status = 'ended';
326	      this.endedAt = Date.now();
327	      this._record({ type: 'session:ended' });
328	      this._broadcastSummary();
329	    }
330	  }
331	
332	  _handleStreamLine(line) {
333	    let evt;
334	    try {
335	      evt = JSON.parse(line);
336	    } catch {
337	      this._record({ type: 'cli:rawline', text: line });
338	      return;
339	    }
340	
341	    // Capture session id if provided.
342	    if (evt.type === 'system' && evt.subtype === 'init' && evt.session_id) {
343	      this.claudeSessionId = evt.session_id;
344	      this._broadcastSummary();
345	    }
346	
347	    // Surface assistant text + tool uses.
348	    if (evt.type === 'assistant' && evt.message && Array.isArray(evt.message.content)) {
349	      for (const block of evt.message.content) {
350	        if (block.type === 'text' && block.text) {
351	          this._record({
352	            type: 'assistant:text',
353	            turnId: this.activeTurn?.id,
354	            text: block.text,
355	          });
356	        } else if (block.type === 'tool_use') {
357	          this._handleToolUse(block);
358	        } else if (block.type === 'thinking' && block.thinking) {
359	          this._record({
360	            type: 'assistant:thinking',
361	            turnId: this.activeTurn?.id,
362	            text: block.thinking,
363	          });
364	        }
365	      }
366	    } else if (evt.type === 'user' && evt.message && Array.isArray(evt.message.content)) {
367	      for (const block of evt.message.content) {
368	        if (block.type === 'tool_result') {
369	          this._record({
370	            type: 'tool:result',
371	            turnId: this.activeTurn?.id,
372	            tool_use_id: block.tool_use_id,
373	            isError: block.is_error || false,
374	            content: extractText(block.content),
375	          });
376	        }
377	      }
378	    } else if (evt.type === 'result') {
379	      this._record({
380	        type: 'turn:result',
381	        turnId: this.activeTurn?.id,
382	        subtype: evt.subtype,
383	        result: evt.result,
384	        durationMs: evt.duration_ms,
385	        usage: evt.usage,
386	        cost: evt.total_cost_usd,
387	      });
388	    } else if (evt.type === 'system') {
389	      // Forward as raw system event for inspectors.
390	      this._record({
391	        type: 'system',
392	        turnId: this.activeTurn?.id,
393	        subtype: evt.subtype,
394	        raw: evt,
395	      });
396	    } else {
397	      // Unknown — keep raw.
398	      this._record({ type: 'cli:event', raw: evt });
399	    }
400	  }
401	
402	  _handleToolUse(block) {
403	    const policy = getPolicy(this.policyId);
404	    const decision = evaluateToolUse(policy, block, { workdir: this.workdir });
405	    const record = {
406	      id: block.id,
407	      turnId: this.activeTurn?.id,
408	      tool: block.name,
409	      input: block.input,
410	      decision: decision.decision,
411	      reason: decision.reason,
412	      ruleMatched: decision.rule?.match || null,
413	      timestamp: Date.now(),
414	    };
415	    this.tools.push(record);
416	    this._record({ type: 'tool:use', ...record });
417	
418	    if (decision.decision === 'manual') {
419	      this.pendingApprovals.set(block.id, record);
420	      this._record({
421	        type: 'approval:pending',
422	        toolUseId: block.id,
423	        tool: block.name,
424	        input: block.input,
425	        reason: decision.reason,
426	      });
427	      this.status = 'waiting';
428	      this._broadcastSummary();
429	    }
430	  }
431	
432	  // The user may resolve a pending manual approval from the UI. Because the
433	  // CLI already executed (or was prevented) by --permission-mode, this resolve
434	  // is informational/audit-only. We still track it so the UX is honest.
435	  resolveApproval(toolUseId, decision, note) {
436	    const rec = this.pendingApprovals.get(toolUseId);
437	    if (!rec) return false;
438	    this.pendingApprovals.delete(toolUseId);
439	    rec.decision = decision; // 'auto' (approved) | 'reject'
440	    rec.manualResolution = decision;
441	    rec.manualNote = note || '';
442	    this._record({
443	      type: 'approval:resolved',
444	      toolUseId,
445	      decision,
446	      note: note || '',
447	    });
448	    if (this.pendingApprovals.size === 0 && this.status === 'waiting') {
449	      this.status = this.activeChild ? 'running' : 'idle';
450	    }
451	    this._broadcastSummary();
452	    return true;
453	  }
454	
455	  _afterTurnFinish(reason) {
456	    const turn = this.activeTurn;
457	    if (turn) {
458	      turn.status = reason;
459	      turn.endedAt = Date.now();
460	    }
461	    this.activeChild = null;
462	
463	    // Compute file changes for the turn.
464	    const changedFiles = this.changeTracker.diff();
465	    if (changedFiles.length > 0 && turn) {
466	      const enriched = changedFiles.map((c) => {
467	        let beforeContent = this.fileBaselines[c.relPath] ?? null;
468	        let afterContent = null;
469	        if (c.kind !== 'deleted') {
470	          const r = this.changeTracker.readFile(c.relPath);
471	          afterContent = r.content;
472	        }
473	        let diffLines = null;
474	        if (beforeContent != null || afterContent != null) {
475	          diffLines = this.changeTracker.unifiedDiff(c.relPath, beforeContent || '', afterContent || '');
476	        }
477	        // Update baseline for next turn.
478	        if (afterContent != null) this.fileBaselines[c.relPath] = afterContent;
479	        else delete this.fileBaselines[c.relPath];
480	
481	        return {
482	          relPath: c.relPath,
483	          kind: c.kind,
484	          size: c.size,
485	          diff: diffLines,
486	        };
487	      });
488	      const changeSet = {
489	        turnId: turn.id,
490	        timestamp: Date.now(),
491	        files: enriched,
492	      };
493	      this.changes.push(changeSet);
494	      for (const f of enriched) {
495	        this.lastChangeMap[f.relPath] = { turnId: turn.id, kind: f.kind };
496	      }
497	      this._record({ type: 'turn:changes', turnId: turn.id, files: enriched });
498	    } else if (turn) {
499	      this._record({ type: 'turn:changes', turnId: turn.id, files: [] });
500	    }
501	
502	    if (turn) this._record({ type: 'turn:end', turnId: turn.id, status: turn.status });
503	
504	    this.activeTurn = null;
505	    this.status = reason === 'error' ? 'error' : 'idle';
506	    this._broadcastSummary();
507	  }
508	
509	  _record(event) {
510	    const enriched = { id: randomUUID(), ts: Date.now(), ...event };
511	    this.events.push(enriched);
512	    if (this.events.length > MAX_EVENTS) {
513	      this.events.splice(0, this.events.length - MAX_EVENTS);
514	    }
515	    this.bus.emit('session:event', { sessionId: this.id, event: enriched });
516	    this._store?.scheduleSave(this);
517	  }
518	
519	  _broadcastSummary() {
520	    this.bus.emit('session:updated', this.summary());
521	  }
522	}
523	
524	function extractText(content) {
525	  if (typeof content === 'string') return content;
526	  if (Array.isArray(content)) {
527	    return content
528	      .map((c) => (typeof c === 'string' ? c : c.text || JSON.stringify(c)))
529	      .join('\n');
530	  }
531	  return '';
532	}
