82	// Evaluate a tool_use event against a policy.
83	// Returns { decision: 'auto'|'manual'|'reject', reason, rule }
84	export function evaluateToolUse(policy, toolUse, ctx = {}) {
85	  const toolName = toolUse.name || toolUse.tool || 'Unknown';
86	  const input = toolUse.input || {};
87	  const workdir = ctx.workdir;
88	
89	  for (const rule of policy.rules) {
90	    const m = rule.match;
91	    if (!m.startsWith('tool:') && !m.startsWith('path:')) continue;
92	
93	    if (m === 'path:outside-workdir' && workdir) {
94	      const targets = collectPathTargets(input);
95	      const outside = targets.find((p) => !isInside(p, workdir));
96	      if (outside) {
97	        return { decision: rule.decision, reason: rule.reason + `（${outside}）`, rule };
98	      }
99	      continue;
100	    }
101	
102	    if (m.startsWith('tool:')) {
103	      const parts = m.slice('tool:'.length).split(':');
104	      const ruleTool = parts[0];
105	      const subPattern = parts.slice(1).join(':');
106	
107	      if (ruleTool !== '*' && ruleTool !== toolName) continue;
108	
109	      if (subPattern) {
110	        // Try matching against bash command
111	        const cmd = input.command || input.cmd || '';
112	        if (!cmd.toLowerCase().includes(subPattern.toLowerCase())) continue;
113	      }
114	      return { decision: rule.decision, reason: rule.reason, rule };
115	    }
116	  }
117	  return { decision: 'manual', reason: '没有命中规则，转人工确认', rule: null };
118	}
119	
120	function collectPathTargets(input) {
121	  const targets = [];
122	  for (const key of ['file_path', 'path', 'notebook_path', 'output_file']) {
123	    if (typeof input[key] === 'string') targets.push(input[key]);
124	  }
125	  return targets;
126	}
127	
128	function isInside(target, workdir) {
129	  if (!target) return true;
130	  let abs = target;
131	  if (!abs.startsWith('/')) abs = workdir.replace(/\/$/, '') + '/' + abs;
132	  const wd = workdir.replace(/\/$/, '');
133	  // Tolerate macOS symlink prefix /tmp <-> /private/tmp
134	  const candidates = [wd];
135	  if (wd.startsWith('/private/')) candidates.push(wd.slice('/private'.length));
136	  else candidates.push('/private' + wd);
137	  return candidates.some((c) => abs === c || abs.startsWith(c + '/'));
138	}
