92	function isGitRepo(dir) {
93	  try {
94	    execFileSync('git', ['-C', dir, 'rev-parse', '--git-dir'], { stdio: 'ignore' });
95	    return true;
96	  } catch {
97	    return false;
98	  }
99	}
