1	// SessionStore — owns all on-disk persistence of Session state.
2	// Single-writer assumption: only one process should manage a given data dir.
3	// Running two `node server.js` against the same dir will clobber writes.
4	import fs from 'node:fs';
5	import path from 'node:path';
6	
7	const VERSION = 1;
8	const DEBOUNCE_MS = 200;
9	const MAX_BASELINE_SIZE = 200_000;
10	
11	export class SessionStore {
12	  constructor({ dir }) {
13	    this.dir = dir;
14	    fs.mkdirSync(dir, { recursive: true });
15	    this._timers = new Map(); // id -> Timeout
16	  }
17	
18	  loadAll() {
19	    const out = [];
20	    let entries;
21	    try {
22	      entries = fs.readdirSync(this.dir, { withFileTypes: true });
23	    } catch {
24	      return out;
25	    }
26	    for (const e of entries) {
27	      if (!e.isFile() || !e.name.endsWith('.json')) continue;
28	      const full = path.join(this.dir, e.name);
29	      try {
30	        const raw = fs.readFileSync(full, 'utf8');
31	        const payload = JSON.parse(raw);
32	        if (this._validate(payload)) {
33	          out.push(payload);
34	        } else {
35	          this._markCorrupt(full);
36	        }
37	      } catch {
38	        this._markCorrupt(full);
39	      }
40	    }
41	    return out;
42	  }
43	
44	  scheduleSave(session) {
45	    const id = session.id;
46	    if (this._timers.has(id)) return;
47	    const timer = setTimeout(() => {
48	      this._timers.delete(id);
49	      this._writeSession(session);
50	    }, DEBOUNCE_MS);
51	    if (typeof timer.unref === 'function') timer.unref();
52	    this._timers.set(id, timer);
53	  }
54	
55	  saveNow(session) {
56	    const t = this._timers.get(session.id);
57	    if (t) {
58	      clearTimeout(t);
59	      this._timers.delete(session.id);
60	    }
61	    this._writeSession(session);
62	  }
63	
64	  flushAll(manager) {
65	    for (const t of this._timers.values()) clearTimeout(t);
66	    this._timers.clear();
67	    for (const session of manager.sessions.values()) {
68	      try {
69	        this._writeSession(session);
70	      } catch (e) {
71	        console.error(`[sessionStore] flush failed ${session.id}:`, e.message);
72	      }
73	    }
74	  }
75	
76	  remove(id) {
77	    const t = this._timers.get(id);
78	    if (t) {
79	      clearTimeout(t);
80	      this._timers.delete(id);
81	    }
82	    const file = path.join(this.dir, `${id}.json`);
83	    try {
84	      fs.unlinkSync(file);
85	    } catch (e) {
86	      if (e.code !== 'ENOENT') {
87	        console.error(`[sessionStore] unlink failed ${id}:`, e.message);
88	      }
89	    }
90	  }
91	
92	  _writeSession(session) {
93	    const payload = serialize(session);
94	    const file = path.join(this.dir, `${session.id}.json`);
95	    const tmp = file + '.tmp';
96	    try {
97	      fs.writeFileSync(tmp, JSON.stringify(payload));
98	      fs.renameSync(tmp, file);
99	    } catch (e) {
100	      console.error(`[sessionStore] write failed ${session.id}:`, e.message);
101	      try { fs.unlinkSync(tmp); } catch {}
102	    }
103	  }
104	
105	  _validate(payload) {
106	    return (
107	      payload &&
108	      payload.version === VERSION &&
109	      typeof payload.id === 'string' &&
110	      typeof payload.workdir === 'string'
111	    );
112	  }
113	
114	  _markCorrupt(filePath) {
115	    try {
116	      fs.renameSync(filePath, filePath + '.corrupt');
117	    } catch {}
118	  }
119	}
120	
121	function serialize(session) {
122	  const fileBaselines = {};
123	  for (const [k, v] of Object.entries(session.fileBaselines || {})) {
124	    if (typeof v !== 'string') continue;
125	    if (v.length > MAX_BASELINE_SIZE) continue;
126	    fileBaselines[k] = v;
127	  }
128	  return {
129	    version: VERSION,
130	    id: session.id,
131	    name: session.name,
132	    workdir: session.workdir,
133	    policyId: session.policyId,
134	    createdAt: session.createdAt,
135	    endedAt: session.endedAt,
136	    status: session.status,
137	    claudeSessionId: session.claudeSessionId,
138	    turns: session.turns,
139	    tools: session.tools,
140	    changes: session.changes,
141	    lastChangeMap: session.lastChangeMap,
142	    fileBaselines,
143	    pendingApprovals: [],
144	    events: session.events,
145	  };
146	}
