35	    if (!fs.existsSync(abs) || !fs.statSync(abs).isDirectory()) {
36	      throw new Error(`工作目录不存在: ${abs}`);
37	    }
38	    // Resolve symlinks (e.g. /tmp -> /private/tmp on macOS) so paths the
39	    // CLI reports later match the workdir we record.
40	    try {
41	      abs = fs.realpathSync(abs);
42	    } catch {}
43	    const session = new Session({
44	      id: nextId(),
45	      workdir: abs,
46	      name: name || path.basename(abs),
47	      policyId: policyId || 'balanced',
48	      bus: this,
49	    });
50	    session._store = this.store;
51	    this.sessions.set(session.id, session);
52	    this.emit('session:created', session.summary());
53	    this.store?.scheduleSave(session);
54	    return session;
55	  }
