336	    } catch {
337	      this._record({ type: 'cli:rawline', text: line });
338	      return;
339	    }
340	
341	    // Capture session id if provided.
342	    if (evt.type === 'system' && evt.subtype === 'init' && evt.session_id) {
343	      this.claudeSessionId = evt.session_id;
344	      this._broadcastSummary();
345	    }
346	
347	    // Surface assistant text + tool uses.
348	    if (evt.type === 'assistant' && evt.message && Array.isArray(evt.message.content)) {
349	      for (const block of evt.message.content) {
350	        if (block.type === 'text' && block.text) {
351	          this._record({
352	            type: 'assistant:text',
353	            turnId: this.activeTurn?.id,
354	            text: block.text,
355	          });
356	        } else if (block.type === 'tool_use') {
357	          this._handleToolUse(block);
358	        } else if (block.type === 'thinking' && block.thinking) {
359	          this._record({
360	            type: 'assistant:thinking',
361	            turnId: this.activeTurn?.id,
362	            text: block.thinking,
363	          });
364	        }
365	      }
366	    } else if (evt.type === 'user' && evt.message && Array.isArray(evt.message.content)) {
367	      for (const block of evt.message.content) {
368	        if (block.type === 'tool_result') {
369	          this._record({
370	            type: 'tool:result',
371	            turnId: this.activeTurn?.id,
372	            tool_use_id: block.tool_use_id,
373	            isError: block.is_error || false,
374	            content: extractText(block.content),
375	          });
376	        }
377	      }
378	    } else if (evt.type === 'result') {
379	      this._record({
380	        type: 'turn:result',
381	        turnId: this.activeTurn?.id,
382	        subtype: evt.subtype,
383	        result: evt.result,
384	        durationMs: evt.duration_ms,
385	        usage: evt.usage,
386	        cost: evt.total_cost_usd,
387	      });
388	    } else if (evt.type === 'system') {
389	      // Forward as raw system event for inspectors.
390	      this._record({
391	        type: 'system',
392	        turnId: this.activeTurn?.id,
393	        subtype: evt.subtype,
394	        raw: evt,
395	      });
396	    } else {
397	      // Unknown — keep raw.
398	      this._record({ type: 'cli:event', raw: evt });
399	    }
400	  }
401	
402	  _handleToolUse(block) {
403	    const policy = getPolicy(this.policyId);
404	    const decision = evaluateToolUse(policy, block, { workdir: this.workdir });
405	    const record = {
406	      id: block.id,
407	      turnId: this.activeTurn?.id,
408	      tool: block.name,
409	      input: block.input,
410	      decision: decision.decision,
411	      reason: decision.reason,
412	      ruleMatched: decision.rule?.match || null,
413	      timestamp: Date.now(),
414	    };
415	    this.tools.push(record);
416	    this._record({ type: 'tool:use', ...record });
417	
418	    if (decision.decision === 'manual') {
419	      this.pendingApprovals.set(block.id, record);
420	      this._record({
421	        type: 'approval:pending',
422	        toolUseId: block.id,
423	        tool: block.name,
424	        input: block.input,
425	        reason: decision.reason,
426	      });
427	      this.status = 'waiting';
428	      this._broadcastSummary();
429	    }
430	  }
431	
432	  // The user may resolve a pending manual approval from the UI. Because the
433	  // CLI already executed (or was prevented) by --permission-mode, this resolve
434	  // is informational/audit-only. We still track it so the UX is honest.
435	  resolveApproval(toolUseId, decision, note) {
436	    const rec = this.pendingApprovals.get(toolUseId);
437	    if (!rec) return false;
438	    this.pendingApprovals.delete(toolUseId);
439	    rec.decision = decision; // 'auto' (approved) | 'reject'
440	    rec.manualResolution = decision;
441	    rec.manualNote = note || '';
442	    this._record({
443	      type: 'approval:resolved',
444	      toolUseId,
445	      decision,
446	      note: note || '',
447	    });
448	    if (this.pendingApprovals.size === 0 && this.status === 'waiting') {
449	      this.status = this.activeChild ? 'running' : 'idle';
450	    }
451	    this._broadcastSummary();
452	    return true;
453	  }
454	
455	  _afterTurnFinish(reason) {
456	    const turn = this.activeTurn;
457	    if (turn) {
458	      turn.status = reason;
459	      turn.endedAt = Date.now();
460	    }
461	    this.activeChild = null;
462	
463	    // Compute file changes for the turn.
464	    const changedFiles = this.changeTracker.diff();
465	    if (changedFiles.length > 0 && turn) {
466	      const enriched = changedFiles.map((c) => {
467	        let beforeContent = this.fileBaselines[c.relPath] ?? null;
468	        let afterContent = null;
469	        if (c.kind !== 'deleted') {
470	          const r = this.changeTracker.readFile(c.relPath);
471	          afterContent = r.content;
472	        }
473	        let diffLines = null;
474	        if (beforeContent != null || afterContent != null) {
475	          diffLines = this.changeTracker.unifiedDiff(c.relPath, beforeContent || '', afterContent || '');
476	        }
477	        // Update baseline for next turn.
478	        if (afterContent != null) this.fileBaselines[c.relPath] = afterContent;
479	        else delete this.fileBaselines[c.relPath];
480	
481	        return {
482	          relPath: c.relPath,
483	          kind: c.kind,
484	          size: c.size,
485	          diff: diffLines,
486	        };
487	      });
488	      const changeSet = {
489	        turnId: turn.id,
490	        timestamp: Date.now(),
491	        files: enriched,
492	      };
493	      this.changes.push(changeSet);
494	      for (const f of enriched) {
495	        this.lastChangeMap[f.relPath] = { turnId: turn.id, kind: f.kind };
496	      }
497	      this._record({ type: 'turn:changes', turnId: turn.id, files: enriched });
498	    } else if (turn) {
499	      this._record({ type: 'turn:changes', turnId: turn.id, files: [] });
500	    }
501	
502	    if (turn) this._record({ type: 'turn:end', turnId: turn.id, status: turn.status });
503	
504	    this.activeTurn = null;
505	    this.status = reason === 'error' ? 'error' : 'idle';
506	    this._broadcastSummary();
507	  }
508	
509	  _record(event) {
510	    const enriched = { id: randomUUID(), ts: Date.now(), ...event };
511	    this.events.push(enriched);
512	    if (this.events.length > MAX_EVENTS) {
513	      this.events.splice(0, this.events.length - MAX_EVENTS);
514	    }
515	    this.bus.emit('session:event', { sessionId: this.id, event: enriched });
516	    this._store?.scheduleSave(this);
517	  }
518	
519	  _broadcastSummary() {
520	    this.bus.emit('session:updated', this.summary());
521	  }
522	}
523	
524	function extractText(content) {
525	  if (typeof content === 'string') return content;
526	  if (Array.isArray(content)) {
527	    return content
528	      .map((c) => (typeof c === 'string' ? c : c.text || JSON.stringify(c)))
529	      .join('\n');
530	  }
531	  return '';
532	}
